            new("s02_full_array",   () => { var a=A(); a[(a%3)==0]=np.array(new long[]{100,200,300,400}); return a; }, new long[]{100,1,2,200,4,5,300,7,8,400,10,11}),
            new("s03_axis0_scalar", () => { var a=A(); a[M(true,false,true)]=(NDArray)(-9L); return a; }, new long[]{-9,-9,-9,-9,4,5,6,7,-9,-9,-9,-9}),
