        // ── DynamicData sources (index + name for readable reporting) ───────────────
        private static IEnumerable<object[]> Idx<T>(T[] arr, Func<T, string> name)
            => arr.Select((c, i) => new object[] { i, name(c) });

        public static IEnumerable<object[]> BoolGetData => Idx(BoolGet, c => c.Name);
        public static IEnumerable<object[]> BoolGetErrData => Idx(BoolGetErr, c => c.Name);
        public static IEnumerable<object[]> BoolSetData => Idx(BoolSet, c => c.Name);
        public static IEnumerable<object[]> BoolSetErrData => Idx(BoolSetErr, c => c.Name);
        public static IEnumerable<object[]> CombGetData => Idx(CombGet, c => c.Name);
        public static IEnumerable<object[]> CombSetData => Idx(CombSet, c => c.Name);
        public static IEnumerable<object[]> CombSetErrData => Idx(CombSetErr, c => c.Name);

        // ── tests ───────────────────────────────────────────────────────────────────
        [DataTestMethod, DynamicData(nameof(BoolGetData))]
        public void BooleanMask_Get(int i, string name) => AssertGet(BoolGet[i]);

        [DataTestMethod, DynamicData(nameof(BoolGetErrData))]
        public void BooleanMask_Get_Throws(int i, string name)
        {
            Action act = () => { var _ = BoolGetErr[i].Op(); };
            act.Should().Throw<Exception>(name);
        }

        [DataTestMethod, DynamicData(nameof(BoolSetData))]
        public void BooleanMask_Set(int i, string name)
        {
            var r = BoolSet[i].Op();
            var flat = new long[r.size];
            var f = r.flat;
            for (long k = 0; k < r.size; k++) flat[k] = Convert.ToInt64(f.GetValue(k));
            flat.Should().Equal(BoolSet[i].Vals, name);
        }

        [DataTestMethod, DynamicData(nameof(BoolSetErrData))]
        public void BooleanMask_Set_Throws(int i, string name)
        {
            Action act = () => { var _ = BoolSetErr[i].Op(); };
            act.Should().Throw<Exception>(name);
        }

        [DataTestMethod, DynamicData(nameof(CombGetData))]
        public void Combined_Get(int i, string name) => AssertGet(CombGet[i]);

        [DataTestMethod, DynamicData(nameof(CombSetData))]
        public void Combined_Set(int i, string name)
        {
            var r = CombSet[i].Op();
            var flat = new long[r.size];
            var f = r.flat;
            for (long k = 0; k < r.size; k++) flat[k] = Convert.ToInt64(f.GetValue(k));
            flat.Should().Equal(CombSet[i].Vals, name);
        }

        [DataTestMethod, DynamicData(nameof(CombSetErrData))]
        public void Combined_Set_Throws(int i, string name)
        {
            Action act = () => { var _ = CombSetErr[i].Op(); };
            act.Should().Throw<Exception>(name);
        }
